import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch13: ScenarioQuestion[] = [
  q("sq-bg13-1",ip,"clinical_judgment","A patient develops fat embolism syndrome after long bone fracture.","How would you recognize fat embolism syndrome?","Fat embolism presents 24-72 hours post-fracture with the classic triad: respiratory distress, neurological changes (confusion, agitation), and petechial rash on the chest, axillae, and conjunctivae. I would provide supportive care with oxygen, monitor neurological status, and anticipate possible intubation. Prevention includes early fracture stabilization.","Fat embolism triad recognition.","advanced"),
  q("sq-bg13-2",ip,"clinical_judgment","A patient develops malignant hyperthermia during anesthesia.","How would you manage malignant hyperthermia?","MH is a life-threatening anesthetic emergency triggered by volatile anesthetics or succinylcholine. It presents with rapidly rising temperature, muscle rigidity, hypercarbia, and metabolic acidosis. I would stop triggering agents, administer dantrolene IV, initiate aggressive cooling, hyperventilate with 100% O2, and treat hyperkalemia. MH mortality is 80% untreated.","Malignant hyperthermia emergency with dantrolene.","advanced"),
  q("sq-bg13-3",ip,"clinical_judgment","A patient develops neuroleptic malignant syndrome.","How does NMS differ from malignant hyperthermia?","NMS is triggered by antipsychotics (not anesthetics), develops over days (not minutes), and presents with hyperthermia, severe muscle rigidity (lead-pipe), autonomic instability, and altered consciousness. Treatment includes stopping the antipsychotic, dantrolene or bromocriptine, supportive cooling, and hydration. CK is markedly elevated from muscle breakdown.","NMS versus MH differentiation.","advanced"),
  q("sq-bg13-4",ip,"clinical_judgment","A patient develops Mallory-Weiss tear from forceful vomiting.","How would you manage a Mallory-Weiss tear?","Mallory-Weiss tear causes upper GI bleeding from a mucosal tear at the gastroesophageal junction, typically after forceful vomiting. Most tears heal spontaneously. I would monitor hemoglobin, provide antiemetics to prevent further vomiting, administer PPI therapy, and prepare for possible endoscopic intervention if bleeding is significant.","Mallory-Weiss tear conservative management.","intermediate"),
  q("sq-bg13-5",ip,"clinical_judgment","A patient develops cholangitis from a bile duct stone.","How would you recognize ascending cholangitis?","Ascending cholangitis presents with Charcot's triad: right upper quadrant pain, jaundice, and fever. Severe cases add confusion and hypotension (Reynolds' pentad). I would ensure blood cultures are drawn, administer IV antibiotics, keep NPO, and prepare for urgent biliary decompression via ERCP. Cholangitis can rapidly progress to septic shock.","Cholangitis Charcot's triad and Reynolds' pentad.","advanced"),
  q("sq-bg13-6",ip,"clinical_judgment","A patient on a beta-blocker develops symptomatic bradycardia.","How would you manage beta-blocker-induced bradycardia?","I would hold the beta-blocker, administer atropine 0.5mg IV for symptomatic bradycardia, prepare for possible transcutaneous pacing if atropine is ineffective, administer glucagon IV (the specific antidote for beta-blocker toxicity—it bypasses the blocked beta receptor), and monitor hemodynamic status. I would not restart the beta-blocker without provider reassessment.","Beta-blocker bradycardia with glucagon antidote.","intermediate"),
  q("sq-bg13-7",ip,"clinical_judgment","A patient develops Boerhaave syndrome from forceful vomiting.","What is Boerhaave syndrome?","Boerhaave syndrome is spontaneous esophageal perforation from forceful vomiting, presenting with severe chest pain, subcutaneous emphysema, and Mackler's triad (vomiting, chest pain, subcutaneous emphysema). This is a surgical emergency with high mortality if untreated. I would keep NPO, administer broad-spectrum antibiotics, prepare for urgent CT and surgical consultation.","Boerhaave syndrome surgical emergency.","advanced"),
  q("sq-bg13-8",ip,"clinical_judgment","A patient develops abdominal aortic aneurysm rupture.","How would you recognize AAA rupture?","Ruptured AAA presents with sudden severe back or abdominal pain, hypotension, and a pulsatile abdominal mass. This is immediately life-threatening. I would establish large-bore IV access, initiate massive transfusion protocol, keep the patient permissively hypotensive (SBP 70-80), and prepare for emergency surgery. Do not delay for imaging if clinical suspicion is high.","AAA rupture emergency management.","advanced"),
  q("sq-bg13-9",ip,"behavioral","You are asked about your experience with technology.","How comfortable are you with healthcare technology?","I embrace technology as a patient safety tool. I am proficient with EHR systems, IV pumps, cardiac monitors, and mobile clinical reference apps. I learn new systems quickly and view technology as enhancing, not replacing, clinical judgment. During clinical, I advocated for using barcode scanning consistently, which prevented a medication error.","Technology as safety tool with specific example.","beginner"),
  q("sq-bg13-10",ip,"behavioral","You are asked about professional integrity.","What does professional integrity mean to you?","Professional integrity means doing the right thing even when no one is watching. It means documenting accurately, admitting mistakes, following evidence-based protocols, advocating for patients, and maintaining ethical standards. Integrity is not situational—it is a consistent commitment that patients and colleagues can rely on.","Consistent integrity philosophy.","beginner"),
  q("sq-bg13-11",ip,"scenario_responses","A patient asks about their prognosis.","How would you respond to prognosis questions?","I would respond within my scope: 'I understand you want to know what to expect. The physician is the best person to discuss your specific prognosis. I can help you prepare questions for when they visit. From a nursing perspective, I can tell you that your [specific indicators] are trending in a positive direction.'","Scope-appropriate prognosis response.","beginner"),
  q("sq-bg13-12",ip,"scenario_responses","A patient is anxious about going home.","How would you address discharge anxiety?","I would validate and address specifics: 'It is completely normal to feel nervous about going home. Let us go through everything together: your medications, when to call the doctor, and what warning signs to watch for. You will also have my unit's phone number if you have questions. You are more prepared than you think.'","Discharge anxiety normalization with preparation.","beginner"),
  q("sq-bg13-13",ip,"star_examples","Describe a time you showed leadership.","Share a leadership example.","During a clinical simulation with 4 students, everyone froze when the scenario escalated. I stepped up and delegated roles: 'You assess airway, you get the cart, you call the physician.' After the simulation, my instructor noted that my calm leadership enabled the team to function effectively. It taught me that leadership is not about hierarchy—it is about stepping up when needed.","Emergent leadership in crisis simulation.","beginner"),
  q("sq-bg13-14",ws,"prioritization","You have a patient with chest pain and the physician is requesting you hold for lab results.","How would you prioritize chest pain versus physician request?","Chest pain takes absolute priority. I would tell the physician: 'I have a patient with new chest pain—I need to assess them immediately. I will call you back with the labs as soon as I can.' I would assess the patient, obtain a 12-lead ECG, and initiate the chest pain protocol before returning to the physician's request.","Chest pain priority over administrative requests.","beginner"),
  q("sq-bg13-15",ws,"prioritization","A post-operative patient reports increasing pain despite scheduled medications.","How would you prioritize escalating post-operative pain?","I would assess the pain immediately: characterize location, quality, and severity; compare to expected post-operative pain; check the surgical site for complications (hematoma, dehiscence, compartment syndrome); review the medication record; and escalate to the physician if pain is disproportionate to the procedure. Unexpected pain escalation may indicate a surgical complication.","Post-operative pain escalation as possible complication.","intermediate"),
  q("sq-bg13-16",ws,"delegation","You need to delegate turning a patient on a ventilator.","How would you delegate ventilator patient repositioning?","I would specify: 'I need help turning Mr. Garcia who is intubated. We need a minimum of 3 people. Secure the ETT during the turn—one person is dedicated to the head and tube. Disconnect the ventilator briefly only if needed, and reconnect immediately. Watch the SpO2 during the turn. Do not pull on any lines. I will manage the ventilator settings.'","Ventilator patient repositioning with ETT security.","intermediate"),
  q("sq-bg13-17",ws,"patient_safety","A patient develops anaphylaxis to a food served in the hospital.","How would you manage food-related anaphylaxis in the hospital?","I would administer epinephrine IM immediately, call for help, ensure patent airway, provide high-flow oxygen, establish IV access, administer diphenhydramine and methylprednisolone, and send the food tray to dietary for investigation. I would update the allergy list, file a safety report, and ensure dietary is notified of the allergen for all future meals.","Hospital food anaphylaxis with dietary notification.","intermediate"),
  q("sq-bg13-18",ws,"patient_safety","A patient develops pressure injury on their sacrum.","How would you manage a new sacral pressure injury?","I would stage the injury, photograph it per facility protocol, initiate a wound care plan, implement pressure redistribution (specialty mattress, repositioning schedule), address nutritional support (protein, vitamins C and A, zinc), optimize moisture management, document comprehensively, and file a safety event report. I would consult wound care nursing for complex injuries.","Sacral pressure injury multi-modal management.","beginner"),
  q("sq-bg13-19",ws,"medication_error","A patient receives a double dose of their blood pressure medication.","How would you manage a double-dose antihypertensive error?","I would check blood pressure and heart rate immediately, monitor for hypotension symptoms (dizziness, syncope), hold the next scheduled dose, notify the provider, and implement fall precautions due to hypotension risk. I would monitor vital signs every 15 minutes for the first hour, then hourly. I would investigate the cause and file a safety report.","Double-dose antihypertensive error response.","beginner"),
  q("sq-bg13-20",ws,"handoff_communication","Your patient had a procedure today and is awaiting results.","How would you communicate pending results during handoff?","I would include: 'Mrs. Rodriguez had a liver biopsy today at 1300. Results are pending—the physician expects preliminary results by morning. She is anxious about the results and has been asking frequently. Her biopsy site has been assessed with no bleeding. She is on bed rest for 4 more hours with vital signs every 2 hours.'","Pending result handoff with emotional context.","beginner"),
  q("sq-bg13-21",ws,"difficult_coworkers","A colleague frequently calls in sick, leaving the unit short-staffed.","How would you handle a colleague's frequent absences?","I would focus on the impact rather than the colleague's behavior: address staffing concerns with the charge nurse and manager, advocate for appropriate staffing ratios, and refuse to accept unsafe assignments. The colleague's attendance is a management issue—my responsibility is ensuring patient safety is not compromised by inadequate staffing.","Staffing impact focus versus colleague behavior.","beginner"),
  q("sq-bg13-22",ws,"interdisciplinary_communication","A case manager recommends a discharge plan you believe is unsafe.","How would you address an unsafe discharge recommendation?","I would articulate my concerns with specific evidence: 'I am concerned about discharging Mr. Lee to home because he cannot perform his wound care independently, has no caregiver support, and his home environment assessment shows barriers to safe mobility. I believe he needs skilled nursing facility placement to prevent readmission.'","Evidence-based discharge safety advocacy.","intermediate"),
  q("sq-bg13-23",ct,"first_shift","You are learning to manage multiple IV infusions simultaneously.","How would you organize multiple IV infusions?","I would label every infusion clearly, trace each line from the pump to the patient, use separate lumens for incompatible medications, set alarms for infusion completion, document flow rates, and perform line assessments every shift. I would create a visual map if needed. Complex IV management requires systematic organization to prevent errors.","Multiple IV infusion management system.","beginner"),
  q("sq-bg13-24",ct,"new_nurse_anxiety","You feel like nursing is not what you expected.","How would you handle disillusionment with nursing?","I would recognize that the gap between nursing school idealism and clinical reality is normal. I would talk to experienced nurses about their early career feelings, explore different nursing specialties that might align better with my interests, and give myself at least a year before making major career decisions. Most nurses find their niche with time and exploration.","Nursing disillusionment normalization.","beginner"),
  q("sq-bg13-25",ct,"time_management","You are behind on charting and your shift ends in 1 hour.","How would you prioritize end-of-shift charting?","I would prioritize: complete critical documentation first (medication administration, assessments, interventions), then update care plans and progress notes. I would use templates for efficiency and focus on accuracy over completeness. If I cannot finish everything, I would communicate specific incomplete items to the oncoming nurse. I would not falsify documentation times.","End-of-shift charting prioritization with honesty.","beginner"),
  q("sq-bg13-26",ct,"documentation_challenges","You need to document a patient's pain assessment comprehensively.","What should a comprehensive pain assessment include?","I would document: pain scale rating (0-10 or appropriate scale), location, quality (sharp, dull, burning, aching), onset and duration, aggravating and alleviating factors, functional impact, current medication effectiveness, non-verbal pain indicators if applicable, and the plan for management. Comprehensive pain assessment drives appropriate treatment.","Comprehensive pain assessment documentation.","beginner"),
  q("sq-bg13-27",ct,"critical_thinking_drills","A patient's white blood cell count is 18,000.","What does leukocytosis indicate?","WBC of 18,000 (normal 4,500-11,000) indicates the immune system is responding to stress, most commonly infection. I would assess for infection sources (respiratory, urinary, wound, bloodstream), check for associated fever, review the differential (left shift with increased bands suggests bacterial infection), and correlate with clinical symptoms. Not all leukocytosis is infectious—stress and steroids also elevate WBC.","Leukocytosis with differential and clinical correlation.","beginner"),
  q("sq-bg13-28",ct,"critical_thinking_drills","A patient's INR is 5.2 on warfarin.","How would you manage a supratherapeutic INR?","INR of 5.2 (therapeutic usually 2-3) increases bleeding risk significantly. I would hold warfarin, assess for active bleeding, notify the provider, anticipate vitamin K administration (oral for non-bleeding, IV for active bleeding), and monitor for signs of hemorrhage. For INR >10 or active bleeding, FFP or PCC may be needed for rapid reversal.","Supratherapeutic INR management stratification.","intermediate"),
  q("sq-bg13-29",pd,"professional_boundaries","A patient requests to follow you on Instagram.","How would you handle social media follow requests from patients?","I would decline kindly: 'I appreciate the connection we have built. However, I keep my professional and personal social media separate. This boundary actually protects your privacy as well as mine. If you need to contact the healthcare team after discharge, please use the hospital contact information.'","Social media patient boundary with privacy rationale.","beginner"),
  q("sq-bg13-30",pd,"ethical_dilemmas","You observe a physician not obtaining informed consent before a procedure.","How would you address missing informed consent?","I would intervene before the procedure: 'Doctor, I want to verify—has informed consent been completed for this procedure? I want to ensure the patient understands the risks and alternatives before we proceed.' If the physician dismisses the concern, I would advocate directly: the patient has a right to informed consent, and proceeding without it is both unethical and illegal.","Informed consent advocacy before procedure.","intermediate"),
  q("sq-bg13-31",pd,"advocacy","A homeless patient is being discharged without a safe destination.","How would you advocate for safe discharge for a homeless patient?","I would involve social work, identify shelter availability, ensure prescriptions are filled before discharge, provide food and hygiene supplies, arrange follow-up at a clinic accessible to the patient, and advocate for extended stay if no safe discharge destination exists. Discharging a medically vulnerable patient to the street is not a safe discharge.","Homeless patient discharge advocacy.","intermediate"),
  q("sq-bg13-32",pd,"patient_communication","A patient asks about second opinions.","How would you support a patient seeking a second opinion?","I would encourage it: 'Getting a second opinion is completely reasonable and your physicians would not be offended. It can provide reassurance or additional treatment options. I can help you obtain copies of your medical records and test results to bring to the consultation. Your active involvement in your care decisions is important.'","Second opinion encouragement.","beginner"),
  q("sq-bg13-33",pd,"workplace_bullying","A charge nurse assigns you the most difficult patients as punishment.","How would you document and address punitive assignments?","I would track the pattern: dates, assignments, and circumstances preceding the assignments. I would present the data objectively to the manager: 'Over the past month, I have received the highest-acuity assignment 12 out of 15 shifts, often following [specific interactions]. I am concerned this may affect patient safety and would appreciate equitable assignment distribution.'","Data-driven punitive assignment report.","intermediate"),
  q("sq-bg13-34",cn,"job_offer_negotiation","You want to ask about professional development support.","How would you negotiate for professional development benefits?","I would ask specifically: 'What professional development support does the organization offer? Specifically, I am interested in certification exam fees, continuing education reimbursement, conference attendance, and tuition assistance for advanced degrees. These investments improve my clinical competence and directly benefit patient care outcomes.'","Specific professional development benefit inquiry.","beginner"),
  q("sq-bg13-35",cn,"probation_period","You receive your first formal evaluation during probation.","How would you maximize your probation evaluation?","I would prepare by: reviewing my self-evaluation honestly, collecting specific examples of growth, identifying areas where I want additional support, bringing documentation of my contributions, and asking for clear expectations for the next evaluation period. I would listen actively, ask clarifying questions, and create an actionable development plan.","Evaluation preparation and actionable planning.","beginner"),
  q("sq-bg13-36",cn,"career_advancement","You want to understand nurse practitioner specialties.","What NP specialty options exist?","NP specialties include: Family NP (across the lifespan), Adult-Gerontology NP (acute or primary care), Pediatric NP, Psychiatric Mental Health NP, Women's Health NP, and Neonatal NP. Each requires specialized graduate education and national certification. Specialty choice should align with clinical interests and career goals. Some specialties have broader practice authority than others.","NP specialty landscape overview.","beginner"),
  q("sq-bg13-37",cn,"performance_evaluation","You want to set meaningful goals during your evaluation.","How would you set SMART nursing goals for your evaluation?","I would create specific, measurable goals: 'Within 6 months, I will independently manage 5-patient assignments with consistent on-time medication administration. Within 12 months, I will obtain ACLS certification and precept one nursing student. I will reduce my documentation time by 20% while maintaining quality.' SMART goals show professional maturity.","SMART nursing goal examples.","beginner"),
  q("sq-bg13-38",ip,"clinical_judgment","A patient develops posterior reversible encephalopathy syndrome.","How would you recognize PRES?","PRES presents with headache, visual disturbances, seizures, and altered consciousness, typically in the setting of severe hypertension, eclampsia, immunosuppressive therapy, or renal disease. MRI shows characteristic posterior white matter edema. Treatment focuses on blood pressure control and removing the precipitating factor. PRES is reversible with prompt treatment.","PRES recognition and reversibility.","advanced"),
  q("sq-bg13-39",ws,"patient_safety","A patient develops hypovolemic shock from GI hemorrhage.","How would you manage hypovolemic shock from GI bleeding?","I would establish two large-bore IV accesses, initiate rapid crystalloid infusion, activate massive transfusion protocol, place an NG tube to assess bleeding, maintain the patient supine, apply supplemental oxygen, monitor vital signs continuously, insert a Foley catheter for output monitoring, and prepare for emergent endoscopy. Type and crossmatch should be done immediately.","GI hemorrhage shock management.","advanced"),
  q("sq-bg13-40",ct,"critical_thinking_drills","A patient's PT/INR shows elevated PT with normal INR.","What could explain elevated PT with normal INR?","This can occur with liver disease where INR calculation may be affected by the ISI of the thromboplastin used, or with specific factor deficiencies. PT measures the extrinsic pathway (factors VII, X, V, II, fibrinogen). I would check additional coagulation studies, assess liver function, and correlate with clinical bleeding risk.","PT/INR discrepancy investigation.","intermediate"),
  q("sq-bg13-41",ip,"clinical_judgment","A patient develops toxic megacolon.","How would you recognize toxic megacolon?","Toxic megacolon presents with severe abdominal distension, high fever, tachycardia, leukocytosis, and systemic toxicity in a patient with colitis (IBD or C. diff). Colon diameter exceeds 6 cm on imaging. This is a surgical emergency—perforation risk is high. I would keep NPO, administer IV antibiotics, avoid anticholinergics and opioids that worsen dilation, and prepare for possible emergent colectomy.","Toxic megacolon recognition and avoidance of worsening agents.","advanced"),
  q("sq-bg13-42",ws,"delegation","You need to delegate feeding a patient with dysphagia.","How would you delegate feeding a dysphagic patient?","I would verify the diet consistency order (mechanical soft, pureed, nectar thick, honey thick), instruct: 'Position upright at 90 degrees, give small spoonfuls, watch for coughing or wet voice quality, allow complete swallowing between bites, and keep upright 30 minutes after eating. Stop feeding and notify me if any signs of aspiration develop.'","Dysphagia feeding delegation with aspiration monitoring.","beginner"),
  q("sq-bg13-43",pd,"ethical_dilemmas","A patient's insurance company denies a necessary treatment.","How would you advocate against insurance denial?","I would support the physician's appeal with nursing documentation of clinical necessity, involve case management and social work, provide the patient with information about their appeal rights, help gather supporting clinical evidence, and explore alternative funding or compassionate use programs. Insurance denial should not prevent access to necessary care.","Insurance denial advocacy.","intermediate"),
  q("sq-bg13-44",cn,"career_advancement","You want to understand the role of nurse navigators.","What does a nurse navigator do?","Nurse navigators guide patients through complex healthcare systems, coordinating appointments, communicating between providers, providing education, addressing barriers to care, and offering emotional support. Common in oncology and chronic disease management. Requirements include clinical experience, strong communication skills, and knowledge of community resources. It combines clinical expertise with care coordination.","Nurse navigator role overview.","beginner"),
  q("sq-bg13-45",ip,"clinical_judgment","A patient develops Ludwig's angina.","What is Ludwig's angina and why is it dangerous?","Ludwig's angina is a rapidly spreading cellulitis of the submandibular space that can occlude the airway. It presents with bilateral submandibular swelling, tongue elevation, drooling, and difficulty breathing. This is an airway emergency. I would maintain airway readiness, administer IV antibiotics, prepare for possible surgical drainage, and have intubation and tracheostomy equipment available.","Ludwig's angina airway emergency.","advanced"),
  q("sq-bg13-46",ws,"patient_safety","A patient on CPAP removes their mask repeatedly during sleep.","How would you manage CPAP non-compliance during hospitalization?","I would assess the reason for removal: mask discomfort, claustrophobia, confusion, or dry mouth. I would try different mask styles, adjust humidification, educate about the importance of CPAP for their condition, offer chin straps for mouth breathing, and document the pattern. For confused patients, I would consider alternatives and notify the respiratory therapist and physician.","CPAP non-compliance troubleshooting.","beginner"),
  q("sq-bg13-47",ct,"documentation_challenges","You need to document care for a patient in seclusion.","What must seclusion documentation include?","I would document: clinical justification for seclusion, physician order with time limits, patient assessment every 15 minutes (vital signs, behavior, safety, elimination needs), attempts at de-escalation, ongoing need reassessment, patient's response to seclusion, offer of food and fluids, and release criteria met. Seclusion documentation is heavily regulated and audited.","Seclusion documentation regulatory requirements.","intermediate"),
  q("sq-bg13-48",pd,"patient_communication","A patient wants to understand their surgical options.","How would you help a patient understand surgical options?","I would facilitate: 'Your surgeon can explain the specific options. To prepare for that conversation, let me help you organize your questions: What are the benefits and risks of each option? What is the recovery time? What does life look like after each option? Writing your questions down ensures you do not forget anything during the discussion.'","Question preparation for surgical decision-making.","beginner"),
  q("sq-bg13-49",cn,"career_advancement","You want to understand the clinical nurse specialist role.","What does a clinical nurse specialist do?","CNSs are advanced practice nurses who function in three spheres: patient/client (expert direct care), nurses/nursing practice (staff development, evidence-based practice), and organization/system (quality improvement, policy development). CNSs hold master's or doctoral degrees and focus on improving outcomes through system-level changes rather than primarily providing direct patient care.","CNS three-sphere role overview.","intermediate"),
  q("sq-bg13-50",ip,"clinical_judgment","A patient develops septic arthritis.","How would you manage septic arthritis?","Septic arthritis presents with acute joint pain, swelling, warmth, and limited range of motion with fever. Joint aspiration is essential for diagnosis and shows turbid fluid with high WBC count. Treatment includes IV antibiotics targeting the most likely organism and possible surgical irrigation. Delayed treatment causes permanent joint damage. I would immobilize the joint and manage pain.","Septic arthritis urgent management.","intermediate"),
  q("sq-bg13-51",ip,"clinical_judgment","A patient develops acute mitral valve regurgitation.","How would you recognize acute MR?","Acute MR presents with sudden onset dyspnea, pulmonary edema, and a new holosystolic murmur at the apex radiating to the axilla. Common causes include papillary muscle rupture post-MI, chordae tendineae rupture, and endocarditis. This is a surgical emergency. I would administer diuretics, vasodilators, and prepare for emergent surgical repair or replacement.","Acute mitral regurgitation emergency.","advanced"),
  q("sq-bg13-52",ws,"medication_error","A nurse asks you to override a medication dispensing cabinet alert.","How would you handle a request to override a dispensing alert?","I would not override without understanding why the alert triggered. Alerts may indicate: dose exceeds maximum, allergy conflict, drug interaction, or wrong patient. I would investigate the alert, contact pharmacy for clarification, and only override with documented clinical justification and pharmacist approval. Overriding alerts defeats the safety purpose of the system.","Dispensing alert investigation before override.","intermediate"),
  q("sq-bg13-53",ct,"critical_thinking_drills","A patient's phosphorus is 1.5 mg/dL.","What does hypophosphatemia cause?","Phosphorus of 1.5 (normal 2.5-4.5) can cause muscle weakness, respiratory failure from diaphragm weakness, hemolytic anemia, impaired oxygen delivery (decreased 2,3-DPG), and confusion. Severe hypophosphatemia (<1.0) is life-threatening. Common in refeeding syndrome and alcoholism. I would administer IV phosphorus replacement, check calcium (inverse relationship), and monitor respiratory status.","Hypophosphatemia multi-system effects.","intermediate"),
  q("sq-bg13-54",pd,"advocacy","A patient is being pressured by family to make a decision they are not ready for.","How would you support patient autonomy against family pressure?","I would advocate: 'I can see your family wants to help, but this is ultimately your decision. You do not have to decide right now. Would you like some time alone to think, or would you like me to help facilitate a conversation where your concerns are heard? I am here to support whatever you decide.'","Patient autonomy protection from family pressure.","intermediate"),
  q("sq-bg13-55",cn,"career_advancement","You want to understand nursing leadership models.","What leadership models are used in nursing?","Common nursing leadership models include: transformational (inspiring change through vision), servant leadership (leader serves the team), shared governance (shared decision-making), and situational leadership (adapting style to the situation). Understanding leadership theory helps you develop your own leadership approach and recognize effective leadership in others.","Nursing leadership model overview.","beginner"),
  q("sq-bg13-56",ip,"clinical_judgment","A patient develops acute aortic regurgitation.","How does acute AR differ from chronic?","Acute aortic regurgitation presents dramatically: sudden heart failure, pulmonary edema, and cardiogenic shock because the left ventricle has not had time to dilate and compensate. Unlike chronic AR which is often asymptomatic for years, acute AR is a surgical emergency. I would administer IV vasodilators and inotropes, avoid IABP (contraindicated in AR), and prepare for emergent valve surgery.","Acute versus chronic AR with IABP contraindication.","advanced"),
  q("sq-bg13-57",ws,"handoff_communication","A patient is receiving a complex wound care regimen.","How would you hand off complex wound care?","I would provide: 'Wound on left lower leg, 4x3cm, stage III, granulating base with 30% slough. Current treatment: enzymatic debridement daily, then hydrogel with foam secondary dressing. Changed today at 1000—next change tomorrow. Drainage moderate serosanguinous. Wound care consult seeing weekly, next visit Wednesday. Photos in the chart for comparison.'","Precise wound care handoff with treatment plan.","intermediate"),
  q("sq-bg13-58",ct,"time_management","You are struggling with work-life boundaries during your first year.","How would you establish work-life boundaries?","I would create intentional transitions: change out of scrubs before going home, develop a decompression routine (exercise, music, shower), avoid checking work email at home, limit nursing discussion outside work, and schedule meaningful non-nursing activities. Sustainable nursing requires deliberate separation between clinical responsibility and personal restoration.","Work-life boundary establishment strategies.","beginner"),
  q("sq-bg13-59",pd,"patient_communication","A patient has low health literacy and struggles with medication instructions.","How would you adapt education for low health literacy?","I would use plain language, limit information to 3 key points per session, use visual aids and pictures, demonstrate rather than explain, use the teach-back method, provide picture-based written materials, involve family support, and schedule follow-up reinforcement sessions. Health literacy is a spectrum—my education approach should match the patient's level.","Low health literacy education adaptation.","beginner"),
  q("sq-bg13-60",cn,"career_advancement","You want to understand nurse coaching.","What is nurse coaching?","Nurse coaches help patients achieve health goals through motivational interviewing, health behavior change strategies, and holistic wellness approaches. Board-certified nurse coaches complete specialized training and certification. This role focuses on empowerment rather than instruction—helping patients discover their own motivation for change. It is a growing specialty with independent practice opportunities.","Nurse coaching career overview.","beginner"),
  q("sq-bg13-61",ip,"clinical_judgment","A patient on LMWH develops major bleeding.","How would you reverse LMWH anticoagulation?","LMWH reversal is challenging because protamine only partially reverses it (60-80% for enoxaparin). I would administer protamine at 1mg per 1mg of enoxaparin if given within 8 hours, provide supportive hemostatic measures, consider tranexamic acid, and monitor anti-Xa levels. For life-threatening bleeding, activated factor VII or PCC may be needed.","LMWH partial reversal with protamine limitations.","advanced"),
  q("sq-bg13-62",ws,"patient_safety","A patient develops acute urticaria to their first dose of a cephalosporin.","Can a penicillin-allergic patient receive cephalosporins?","Cross-reactivity between penicillins and cephalosporins is approximately 1-2%—much lower than previously believed. However, I would verify the specific penicillin allergy: patients with a history of anaphylaxis to penicillin should avoid first-generation cephalosporins. Second and third-generation cephalosporins have lower cross-reactivity. I would always have epinephrine available for first-dose cephalosporin administration in penicillin-allergic patients.","Penicillin-cephalosporin cross-reactivity evidence.","intermediate"),
  q("sq-bg13-63",ct,"documentation_challenges","You need to document patient education with teach-back.","How would you document teach-back verification?","I would document: 'Diabetes management education provided. Topics covered: blood glucose monitoring technique, insulin injection sites, hypoglycemia recognition and treatment, and dietary modifications. Patient demonstrated correct technique for blood glucose monitoring and insulin injection. Patient correctly identified 3 hypoglycemia symptoms and appropriate treatment. Education materials provided. Will reassess understanding before discharge.'","Teach-back verification documentation.","beginner"),
  q("sq-bg13-64",pd,"ethical_dilemmas","A research nurse asks you to approach a vulnerable patient for study enrollment.","How would you protect vulnerable patients in research?","I would ensure the patient is not coerced or unduly influenced, verify IRB approval, confirm the patient understands participation is voluntary, assess their decision-making capacity, ensure adequate time for consideration without pressure, and report any concerns about undue influence to the IRB. Vulnerable patients need additional protection in research.","Vulnerable patient research protection.","intermediate"),
  q("sq-bg13-65",cn,"career_advancement","You want to understand healthcare informatics trends.","What informatics skills will be important for future nursing?","Key informatics trends: artificial intelligence in clinical decision support, telehealth expansion, wearable health monitoring, interoperability between systems, data analytics for population health, cybersecurity in healthcare, and patient engagement technology. Nurses with informatics skills will be increasingly valuable as healthcare technology evolves.","Future nursing informatics trends.","intermediate"),
  q("sq-bg13-66",ip,"clinical_judgment","A patient develops mesenteric venous thrombosis.","How would you manage mesenteric venous thrombosis?","MVT presents with gradual onset abdominal pain, often with portal hypertension or hypercoagulable states. Unlike arterial mesenteric ischemia, MVT progresses more slowly. Treatment includes anticoagulation with heparin, bowel rest, and monitoring for bowel infarction signs. Surgery is reserved for peritonitis or perforation. Long-term anticoagulation is usually needed.","Mesenteric venous thrombosis versus arterial ischemia.","advanced"),
  q("sq-bg13-67",ws,"delegation","You need to delegate collecting a stool specimen.","How would you delegate stool specimen collection?","I would specify: 'Please collect a stool specimen from Mrs. Adams using the labeled container. Wear gloves and use the collection hat. Do not contaminate the specimen with urine or toilet water. Label the container with the patient's name, date, and time. Transport it to the lab within 30 minutes or refrigerate it. Let me know when it is collected.'","Stool specimen collection delegation with contamination prevention.","beginner"),
  q("sq-bg13-68",ct,"new_nurse_anxiety","You are worried about calling in sick when you are genuinely ill.","How would you decide whether to call in sick?","I would consider: Am I able to provide safe patient care? Could I transmit illness to vulnerable patients? Would I be a liability rather than an asset to my team today? Coming to work sick compromises patient safety and prolongs my recovery. I would notify my charge nurse early, follow facility call-in procedures, and not feel guilty about protecting my patients.","Appropriate sick call decision-making.","beginner"),
  q("sq-bg13-69",pd,"advocacy","A patient is being bullied by their hospital roommate.","How would you address patient-to-patient bullying?","I would ensure the affected patient feels safe, address the behavior with the offending patient, arrange room reassignment if possible, involve patient services, and document the situation. Every patient deserves a therapeutic healing environment. Patient-to-patient conflict that rises to bullying requires nursing intervention and administrative support.","Patient-to-patient bullying intervention.","beginner"),
  q("sq-bg13-70",cn,"career_advancement","You are considering per diem nursing.","What are the pros and cons of per diem nursing?","Per diem offers: scheduling flexibility, often higher hourly rates, exposure to diverse clinical experiences, and freedom from committee obligations. Challenges include: no guaranteed hours, limited benefits, no seniority for scheduling, and less team integration. Per diem nursing is best for experienced nurses who value flexibility and can maintain clinical competence independently.","Per diem nursing evaluation.","beginner"),
  q("sq-bg13-71",ip,"clinical_judgment","A patient develops type II second-degree heart block.","How would you manage Mobitz type II heart block?","Mobitz type II shows dropped QRS complexes without progressive PR prolongation—the block is below the AV node. Unlike type I (Wenckebach), type II is more dangerous and can progress to complete heart block without warning. I would prepare for temporary pacing, avoid atropine (may worsen infranodal blocks), and notify the cardiologist for possible permanent pacemaker.","Mobitz type II management with atropine caution.","advanced"),
  q("sq-bg13-72",ws,"interdisciplinary_communication","A patient needs a nutrition assessment but the dietitian has a 3-day wait.","How would you manage a nutrition delay?","I would initiate nursing nutritional screening using validated tools, document my findings, implement basic nutritional interventions within my scope, communicate the urgency of the consultation with dietary management, and escalate through the charge nurse if the patient's nutritional status is deteriorating. Waiting 3 days for a nutritional assessment may not be appropriate for all patients.","Nutrition assessment delay advocacy with interim intervention.","beginner"),
  q("sq-bg13-73",ct,"critical_thinking_drills","A patient's blood cultures grow Staphylococcus epidermidis.","Is S. epidermidis bacteremia always significant?","S. epidermidis is a common contaminant but can cause true infection, especially in patients with prosthetic devices (heart valves, joint replacements, central lines). Significance is determined by: number of positive bottles, clinical symptoms, and presence of foreign material. One positive bottle is likely contamination; multiple positive bottles suggest true infection.","S. epidermidis true infection versus contamination.","intermediate"),
  q("sq-bg13-74",pd,"patient_communication","A patient is making end-of-life decisions.","How would you support end-of-life decision-making?","I would create a calm, private environment, ensure the patient has accurate clinical information, explore their values and what matters most to them, involve loved ones if the patient wishes, offer spiritual support resources, and ensure they understand all options including comfort care. End-of-life conversations require presence, patience, and genuine compassion.","End-of-life decision support approach.","intermediate"),
  q("sq-bg13-75",cn,"career_advancement","You want to understand quality improvement methodology.","What QI methodologies should nurses understand?","Key QI methodologies: Plan-Do-Study-Act (PDSA) cycles for rapid improvement, Lean for waste reduction, Six Sigma for defect reduction, Root Cause Analysis for incident investigation, and Failure Mode and Effects Analysis for proactive risk identification. Understanding QI methodology enables nurses to lead improvement projects and contribute to organizational quality goals.","QI methodology overview for nurses.","intermediate"),
  q("sq-bg13-76",ip,"clinical_judgment","A patient develops complete heart block.","How would you manage third-degree heart block?","Complete heart block shows complete AV dissociation—atria and ventricles beat independently. The ventricular escape rate determines urgency: junctional escape (40-60 bpm) is more stable than ventricular escape (20-40 bpm). I would prepare for temporary transcutaneous pacing, have atropine available (though it may be ineffective for infranodal blocks), and prepare for permanent pacemaker placement.","Complete heart block with escape rate assessment.","advanced"),
  q("sq-bg13-77",ws,"patient_safety","A patient develops hospital-acquired pneumonia.","How would you identify and help prevent hospital-acquired pneumonia?","HAP develops 48+ hours after admission. Prevention includes: oral care every 4 hours, head of bed elevation 30 degrees, early mobilization, incentive spirometry, aspiration risk assessment, swallowing evaluation when indicated, and hand hygiene. I would monitor for new fever, productive cough, increased oxygen requirements, and new infiltrate on chest X-ray.","HAP prevention bundle and recognition.","beginner"),
  q("sq-bg13-78",ct,"time_management","You want to develop a reliable shift organization system.","How would you create a personal shift organization system?","I would develop a consistent brain sheet that includes: patient overview, scheduled medications and times, procedures, pending labs and results, assessments due, discharge planning steps, and blank space for notes. I would review and update it hourly. Consistent systems prevent forgotten tasks and reduce cognitive load during complex shifts.","Personal brain sheet organization system.","beginner"),
  q("sq-bg13-79",pd,"ethical_dilemmas","A patient asks you to help them access medical marijuana.","How would you respond to medical marijuana inquiries?","I would respond within my scope: 'Medical marijuana laws vary by state. I can not prescribe or obtain it for you, but I can provide information about your state's medical marijuana program and suggest you discuss it with your physician. If your state allows it, your doctor can evaluate whether it might benefit your condition.'","Medical marijuana scope-appropriate response.","beginner"),
  q("sq-bg13-80",cn,"career_advancement","You want to understand nurse leadership development programs.","What leadership development programs exist for nurses?","Options include: AONE nurse manager fellowship, emerging nurse leader programs through professional organizations, hospital-based leadership academies, Executive MBA with healthcare focus, clinical ladder programs that develop leadership alongside clinical expertise, and mentorship programs with established leaders. Formal leadership development accelerates career progression.","Nurse leadership program landscape.","beginner"),
  q("sq-bg13-81",ip,"clinical_judgment","A patient develops posterior wall MI.","How would you recognize a posterior wall MI?","Posterior wall MI often presents with reciprocal ST depression in V1-V3 (tall R waves, ST depression instead of typical elevation). It is missed frequently because standard 12-lead ECG does not directly view the posterior wall. I would obtain posterior leads (V7-V9) if posterior MI is suspected, especially with inferior MI. Prompt recognition is critical for timely PCI.","Posterior MI recognition with posterior leads.","advanced"),
  q("sq-bg13-82",ws,"medication_error","A patient questions why their medication schedule changed.","How would you explain medication schedule changes?","I would investigate before explaining: verify the order, check with pharmacy for timing changes, and ensure the change is intentional. Then I would explain: 'Your medication timing was adjusted because [specific reason—new medication interaction, lab result, or physician order change]. This new schedule is designed to optimize the medication's effectiveness.'","Schedule change investigation and explanation.","beginner"),
  q("sq-bg13-83",ct,"documentation_challenges","You need to document a patient's decisional capacity assessment.","How would you document capacity assessment?","I would document: 'Patient assessment for decisional capacity: Patient can communicate a choice clearly. Patient understands their diagnosis and proposed treatment as demonstrated by stating: [specific patient statement]. Patient appreciates the consequences of accepting and refusing treatment. Patient demonstrates logical reasoning about the decision. Capacity is present/absent based on this assessment.'","Capacity assessment documentation framework.","intermediate"),
  q("sq-bg13-84",pd,"patient_communication","A patient is in denial about their substance use disorder.","How would you approach a patient in denial about substance abuse?","I would use motivational interviewing: 'I am not here to judge. I am noticing that your lab results and symptoms suggest your body is being affected by substance use. How do you see your substance use? What would it take for you to consider making a change?' I would meet them where they are, not where I want them to be.","Motivational interviewing for substance use denial.","intermediate"),
  q("sq-bg13-85",cn,"career_advancement","You want to understand evidence-based practice implementation.","How do you implement evidence-based practice changes?","EBP implementation follows the PICO framework: identify the clinical Problem, determine the Intervention, compare with current practice (Comparison), and define the desired Outcome. Steps include: formulating the question, searching for best evidence, critically appraising the evidence, implementing the change, and evaluating outcomes. EBP bridges research and clinical practice.","PICO framework for EBP implementation.","beginner"),
  q("sq-bg13-86",ip,"clinical_judgment","A patient develops right-sided heart failure.","How does right-sided heart failure present differently from left-sided?","Right-sided HF presents with systemic congestion: JVD, hepatomegaly, peripheral edema, ascites, and weight gain. Left-sided HF presents with pulmonary congestion: dyspnea, orthopnea, crackles, and pulmonary edema. Right failure often results from left failure (backward pressure), COPD, or pulmonary hypertension. I would assess for both sides and correlate with BNP and imaging.","Left versus right heart failure presentation.","intermediate"),
  q("sq-bg13-87",ws,"patient_safety","A patient on airborne precautions needs emergent intubation.","How would you balance PPE with emergent intubation?","Intubation is an aerosol-generating procedure requiring N95, eye protection, gown, and gloves. For emergent situations, I would don N95 and gloves at minimum before entering, with other team members donning full PPE as they arrive. Video laryngoscopy is preferred to minimize provider exposure. Delay in airway management for PPE must be balanced against infection risk.","Emergent airway PPE balance.","intermediate"),
  q("sq-bg13-88",ct,"critical_thinking_drills","A patient's hemoglobin electrophoresis shows elevated HbS.","What does elevated HbS indicate?","Elevated HbS indicates sickle cell disease (HbSS) or sickle cell trait (HbAS). In sickle cell disease, HbS is 80-100% and causes vaso-occlusive crises, acute chest syndrome, and hemolytic anemia. In sickle cell trait, HbS is 20-40% and is usually asymptomatic. I would assess for pain crisis symptoms, ensure adequate hydration, and provide oxygen if SpO2 is low.","Hemoglobin electrophoresis interpretation for sickle cell.","intermediate"),
  q("sq-bg13-89",pd,"advocacy","A patient's advance directive conflicts with the treatment plan.","How would you advocate for advance directive compliance?","I would bring the discrepancy to the physician's attention: 'The patient's advance directive specifies no mechanical ventilation, but the current treatment plan includes intubation if they deteriorate. Can we discuss aligning the care plan with the patient's documented wishes?' Advance directives reflect the patient's autonomous decisions and should guide care.","Advance directive compliance advocacy.","intermediate"),
  q("sq-bg13-90",cn,"career_advancement","You want to maximize your continuing education impact.","How would you choose CE courses strategically?","I would align CE with: my specialty certification maintenance requirements, identified knowledge gaps from clinical practice, career advancement goals, and emerging healthcare trends. I would prioritize interactive CE over passive reading, apply new knowledge to clinical practice within a week of completion, and share relevant CE content with my team during unit meetings.","Strategic CE selection and application.","beginner"),
  q("sq-bg13-91",ip,"clinical_judgment","A patient develops atrial flutter.","How would you recognize and manage atrial flutter?","Atrial flutter shows a characteristic sawtooth pattern on ECG with atrial rate of 300 bpm, typically with 2:1 block giving a ventricular rate of 150. Treatment depends on stability: synchronized cardioversion for unstable patients, IV diltiazem or beta-blockers for rate control in stable patients. Anticoagulation considerations are similar to atrial fibrillation.","Atrial flutter recognition and management.","intermediate"),
  q("sq-bg13-92",ws,"handoff_communication","You are transferring a patient to the ICU.","What information is critical for a floor-to-ICU transfer?","I would communicate: reason for transfer, current vital signs and trends, pertinent assessment changes, current IV lines and infusions, respiratory support, code status, medication list with recent changes, relevant labs, provider notifications and responses, family awareness of transfer, and any anticipated deterioration concerns.","Floor-to-ICU transfer critical communication.","beginner"),
  q("sq-bg13-93",ct,"first_shift","You need to manage your first patient on a ventilator.","How would you approach your first ventilated patient?","I would review ventilator settings with respiratory therapy, understand the mode and parameters, verify all alarm settings, perform respiratory assessments every 2 hours, ensure ambu bag is at bedside, assess oral care needs, monitor for ventilator-associated complications, and communicate any changes in patient status immediately to the RT and physician.","First ventilator patient management preparation.","intermediate"),
  q("sq-bg13-94",pd,"professional_boundaries","You feel emotionally attached to a patient who reminds you of a family member.","How would you manage transference in patient care?","I would recognize the emotional connection, discuss it with a trusted colleague, maintain professional boundaries despite the attachment, ensure my emotional response does not influence clinical decisions, and seek supervision if the transference affects my objectivity. Awareness of transference is the first step to managing it professionally.","Transference recognition and professional management.","intermediate"),
  q("sq-bg13-95",cn,"performance_evaluation","You want to demonstrate quality improvement contributions.","How would you document QI contributions for your evaluation?","I would present: problem identified, data collected, intervention implemented, and measurable outcomes. For example: 'I noticed inconsistent hand hygiene compliance during shift change. I proposed a visual reminder system at every doorway, implemented with charge nurse approval. Compliance monitoring showed improvement from 78% to 94% over 3 months.'","QI contribution with measurable outcomes.","beginner"),
  q("sq-bg13-96",ip,"clinical_judgment","A patient develops supraventricular tachycardia.","How would you manage SVT?","SVT presents with regular narrow-complex tachycardia, often 150-250 bpm. For stable SVT, I would attempt vagal maneuvers (Valsalva, carotid massage, ice to the face), then administer adenosine 6mg rapid IV push followed by 12mg if needed. Adenosine causes brief asystole that resets the cardiac rhythm. For unstable SVT, synchronized cardioversion is required.","SVT management with adenosine technique.","intermediate"),
  q("sq-bg13-97",ws,"patient_safety","A patient develops hospital-acquired Clostridioides difficile from antibiotic exposure.","How would you prevent C. diff spread?","I would implement strict contact precautions, use soap and water for hand hygiene (alcohol does not kill spores), clean the environment with bleach-based solutions, ensure dedicated equipment, educate visitors about hand washing, advocate for antibiotic stewardship, and avoid unnecessary proton pump inhibitors which increase C. diff risk.","C. diff transmission prevention.","beginner"),
  q("sq-bg13-98",ct,"critical_thinking_drills","A patient's CO2 is 58 mmHg on ABG.","What does a CO2 of 58 indicate?","CO2 of 58 (normal 35-45) indicates hypoventilation and respiratory acidosis. The patient is not exhaling enough CO2. Causes include COPD exacerbation, oversedation, neuromuscular disease, and obesity hypoventilation syndrome. I would assess respiratory rate and effort, check SpO2, consider whether this is acute or chronic (compensated pH suggests chronic), and prepare for possible ventilatory support.","Respiratory acidosis assessment acute versus chronic.","intermediate"),
  q("sq-bg13-99",pd,"ethical_dilemmas","A patient asks you to destroy a legal document.","How would you handle a request to destroy documents?","I would decline: 'I cannot destroy any legal or medical documents. If you have concerns about a document, I can connect you with patient services or a legal advocate who can help you understand your options.' Destroying documents could have legal consequences for both of us. I would document the request and follow facility policy.","Document destruction refusal.","beginner"),
  q("sq-bg13-100",cn,"career_advancement","You want to build your professional network.","How would you build a professional nursing network?","I would join professional nursing organizations, attend local chapter meetings, participate in online nursing communities, connect with colleagues at conferences, maintain relationships with nursing school classmates and instructors, volunteer for professional committees, and develop genuine relationships through shared professional interests. A strong network provides support, mentorship, and career opportunities.","Professional network building strategy.","beginner"),
];
